import React, { useState } from "react";
import "./styles.css";

const Button = () => {
  const [sum, setSum] = useState(0);
  const [first, setFirst] = useState(0);
  const [second, setSecond] = useState(0);
  const add = () => {
      setFirst((first) => parseInt(document.getElementById("firstnumber").value)
       );

        setSecond((second) => parseInt(document.getElementById("secondnumber").value)
       );
      setSum((sum) => first + second);

}
  return (
    <div className="Button">

      <body>
      <p>First Number: <input id="firstnumber"/> </p>
      <p>Second Number: <input id="secondnumber" /> </p>
     <button onClick={add}>Add Them</button>
      <p>Sum = {sum} </p>
   </body>

    </div>
  );
};

export default Button;
